 1→export interface TelegramRichMessageDraft {
 2→  markdown: string;
 3→}
 4→
 5→export function renderTelegramRichDraft(text: string): TelegramRichMessageDraft {
 6→  return { markdown: text.replace(/\r\n/g, "\n") };
 7→}
