38→/**
39→ * Send a new rich message (for multi-chunk continuation messages).
40→ * Rich sends go through the dedicated Bot API 10.1 `sendRichMessage` method —
41→ * `sendMessage` ignores a `rich_message` param and delivers plain text.
42→ * Returns the sent message object, or undefined if rich send is unsupported
43→ * or rejected (caller falls back to a plain send).
44→ */
45→export async function trySendRichMessage(
46→  api: unknown,
47→  chatId: number,
48→  text: string,
49→  extra: Record<string, unknown> = {},
50→): Promise<{ message_id: number } | undefined> {
51→  const raw = (api as { raw?: { sendRichMessage?: unknown } }).raw;
52→  const method = raw?.sendRichMessage;
53→  if (typeof method !== "function") return undefined;
54→  const rich_message = renderTelegramRichDraft(text);
